    public function index(Request $request)
    {
        $items = $this->getItems();

        // Search filter
        if ($request->search) {
            $items = collect($items)->filter(function ($item) use ($request) {
                return stripos($item['title'], $request->search) !== false;
            })->values();
        }

        // Pagination (4 per page)
        $page = $request->get('page', 1);
        $perPage = 8;
        $total = count($items);
        $items = collect($items)->slice(($page - 1) * $perPage, $perPage)->all();

        $paginator = new \Illuminate\Pagination\LengthAwarePaginator(
            $items, $total, $perPage, $page,
            ['path' => url('/items'), 'query' => $request->query()]
        );

        return view('items.index', ['items' => $paginator]);
    }

    public function show($id)
    {
        $items = $this->getItems();
        $item = collect($items)->firstWhere('id', $id);
        if (!$item) abort(404);

        return view('items.show', compact('item'));
    }
